def count_new_items_recursive(path: str, max_date) -> int:
    if isinstance(max_date, str):
        max_date = datetime.strptime(
            max_date, "%Y-%m-%dT%H:%M:%S.%f+0000" )
    count = 0
    try:
        items = mssparkutils.fs.ls(path)
        for item in items:
            if item.isDir:
                count += count_new_items_recursive(item.path, max_date)
            else:
                match = re.search(
                    r'(\d{4}-\d{2}-\d{2}T\d{2}_\d{2}_\d{2}\.\d{6}\+0000)',
                    item.path)
                if not match:
                    continue
                file_timestamp_str = match.group(1)
                file_timestamp_str = file_timestamp_str.replace("_", ":")
                item_time = datetime.strptime(file_timestamp_str,"%Y-%m-%dT%H:%M:%S.%f+0000")
                if max_date is None or item_time > max_date:
                    count += 1
    except Exception as e:
        print(f"Error reading path {path}: {e}")
    return count
